# Shape classes module - base class and related types

class Shape:
    """Base class for all shapes"""
    def __init__(self, name: str):
        self.name = name

    @virtual
    def area(self) -> float:
        return 0.0

    @virtual
    def describe(self) -> str:
        return "Shape: " + self.name

