# Rectangle classes module - demonstrates inheritance across modules
from shapes import Shape

class Rectangle(Shape):
    """Rectangle shape with width and height"""
    def __init__(self, width: float, height: float):
        super().__init__("Rectangle")
        self._width = width
        self._height = height

    property get width(self) -> float:
        return self._width

    property get height(self) -> float:
        return self._height

    @override
    def area(self) -> float:
        return self._width * self._height

    @override
    def describe(self) -> str:
        return self.name + " " + self._width + " x " + self._height

class Square(Rectangle):
    """Square is a special rectangle"""
    def __init__(self, side: float):
        super().__init__(side, side)
        self.name = "Square"

