# Utility functions module for shape operations
from rectangles import Rectangle
from shapes import Shape

def calculate_total_area(rectangles: list[Rectangle]) -> float:
    """Calculate total area of all rectangles"""
    total: float = 0.0
    for rect in rectangles:
        total += rect.area()
    return total

def create_description(shape: Shape) -> str:
    """Create a description of any shape"""
    return shape.describe()
